// innerHTML nümunəsi
const container = document.querySelector('#myContainer');
console.log('İlkin məzmun:', container.innerHTML); // HTML məzmununu konsola yazdırır
container.innerHTML = '<p>Yeni paraqraf</p><b>Qalın mətn</b>'; // Yeni HTML məzmunu əlavə edir

// innerText nümunəsi
const container = document.querySelector('#myContainer');
console.log('İlkin mətn:', container.innerText); // Görünən mətni konsola yazdırır
container.innerText = 'Yeni görünən mətn'; // Yalnız mətni dəyişdirir

// textContent nümunəsi
const container = document.querySelector('#myContainer');
console.log('İlkin mətn:', container.textContent); // Bütün mətni konsola yazdırır
container.textContent = 'Yeni mətn <b>qalın</b>'; // Mətn kimi əlavə olunur, teqlər işlədilmir

// Hadisə ilə məzmun dəyişdirmə nümunəsi
const button = document.querySelector('#myButton');
const container = document.querySelector('#myContainer');
button.addEventListener('click', () => {
  container.innerHTML = '<p>Yeni HTML məzmunu</p>';
  console.log('Məzmun dəyişdirildi');
});

// Səhvə yol açan nümunə
const element = document.querySelector('#nonExistent');
element.innerHTML = 'Yeni məzmun'; // TypeError: Cannot set property 'innerHTML' of null

// Düzgün yol
const safeElement = document.querySelector('#nonExistent');
if (safeElement) {
  safeElement.innerHTML = 'Yeni məzmun';
} else {
  console.log('Element tapılmadı');
}

// innerHTML example
const container = document.querySelector('#myContainer');
console.log('Initial content:', container.innerHTML); // Logs the HTML content
container.innerHTML = '<p>New paragraph</p><b>Bold text</b>'; // Adds new HTML content

// innerText example
const container = document.querySelector('#myContainer');
console.log('Initial text:', container.innerText); // Logs visible text
container.innerText = 'New visible text'; // Changes only the text

// textContent example
const container = document.querySelector('#myContainer');
console.log('Initial text:', container.textContent); // Logs all text
container.textContent = 'New text <b>bold</b>'; // Adds as text, tags are not processed

// Event-driven content change example
const button = document.querySelector('#myButton');
const container = document.querySelector('#myContainer');
button.addEventListener('click', () => {
  container.innerHTML = '<p>New HTML content</p>';
  console.log('Content changed');
});

// Error-prone example
const element = document.querySelector('#nonExistent');
element.innerHTML = 'New content'; // TypeError: Cannot set property 'innerHTML' of null

// Correct approach
const safeElement = document.querySelector('#nonExistent');
if (safeElement) {
  safeElement.innerHTML = 'New content';
} else {
  console.log('Element not found');
}

// Пример innerHTML
const container = document.querySelector('#myContainer');
console.log('Исходное содержимое:', container.innerHTML); // Выводит HTML-содержимое
container.innerHTML = '<p>Новый параграф</p><b>Жирный текст</b>'; // Добавляет новое HTML-содержимое

// Пример innerText
const container = document.querySelector('#myContainer');
console.log('Исходный текст:', container.innerText); // Выводит видимый текст
container.innerText = 'Новый видимый текст'; // Изменяет только текст

// Пример textContent
const container = document.querySelector('#myContainer');
console.log('Исходный текст:', container.textContent); // Выводит весь текст
container.textContent = 'Новый текст <b>жирный</b>'; // Добавляет как текст, теги не обрабатываются

// Пример изменения содержимого с событием
const button = document.querySelector('#myButton');
const container = document.querySelector('#myContainer');
button.addEventListener('click', () => {
  container.innerHTML = '<p>Новое HTML-содержимое</p>';
  console.log('Содержимое изменено');
});

// Пример с ошибкой
const element = document.querySelector('#nonExistent');
element.innerHTML = 'Новое содержимое'; // TypeError: Cannot set property 'innerHTML' of null

// Правильный подход
const safeElement = document.querySelector('#nonExistent');
if (safeElement) {
  safeElement.innerHTML = 'Новое содержимое';
} else {
  console.log('Элемент не найден');
}
